INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, 11, 0, 19230021, "フードコートで売っているのであれば\n何ら違和感はないけれど。", 115711, 1, 10, 923, 0, 0.5);
