INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, 11, 0, 19450033, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 122611, 1, 5, 945, 0, 1);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES ("", 91, "", 19450034, "", 0, "", "", 945, "", "");
